SELECT a.name
FROM artists a
WHERE CAST(a.total_streams AS REAL) = (
    SELECT MAX(CAST(total_streams AS REAL))
    FROM artists
);

SELECT COUNT(follower_id) AS follower_count
FROM follows
WHERE following_id = 0;

SELECT name AS artist_name
FROM artists
WHERE total_followers > 10000;

SELECT AVG(total_followers) AS avg_followers
FROM artists
WHERE is_active = 1 AND total_followers > 500000;
